import type { Shoe } from "@/types";

// All prices stored in USD. Display layer converts via RegionContext.
// Lab data sourced from brand spec sheets, Running Warehouse, and published reviews.
// Scores are editorial aggregates from major review sources.

type S = Shoe;
const ph = (base: number): Shoe["priceHistory"] => [
  { month:"Oct", price: Math.round(base*1.0) },
  { month:"Nov", price: Math.round(base*0.95) },
  { month:"Dec", price: Math.round(base*0.85) },
  { month:"Jan", price: Math.round(base*1.0) },
  { month:"Feb", price: Math.round(base*0.91) },
  { month:"Mar", price: Math.round(base*1.0) },
  { month:"Apr", price: Math.round(base*0.94) },
];
const ret = (name:string, price:number): Shoe["retailers"] => [
  { name, price, url:"#", inStock:true },
  { name:"Amazon", price:Math.round(price*1.03), url:"#", inStock:true },
];

